import { describe, expect, it } from "vitest";
import { makeUserService } from "../src/userService.js";

describe("makeUserService.getUsers", () => {
  it("does not serve archived users to a caller that excluded them", async () => {
    const loadUsers = async ({ includeArchived }) =>
      includeArchived ? ["alice", "bob(archived)"] : ["alice"];

    const service = makeUserService(loadUsers);

    // An admin view warms the cache including archived users.
    const withArchived = await service.getUsers({
      team: "eng",
      includeArchived: true,
    });
    expect(withArchived).toEqual(["alice", "bob(archived)"]);

    // The people picker asks for the same team WITHOUT archived users.
    const pickerUsers = await service.getUsers({
      team: "eng",
      includeArchived: false,
    });
    expect(pickerUsers).toEqual(["alice"]);
  });

  it("still caches within the same opts", async () => {
    let calls = 0;
    const loadUsers = async () => {
      calls += 1;
      return ["alice"];
    };
    const service = makeUserService(loadUsers);
    await service.getUsers({ team: "eng", includeArchived: false });
    await service.getUsers({ team: "eng", includeArchived: false });
    expect(calls).toBe(1);
  });
});

